SELECT COUNT(*) AS total_accesses
FROM access_logs
WHERE experiment_id = (SELECT experiment_id FROM experiments WHERE experiment_name = 'Quantum Physics Experiment');

SELECT track_id, experiment_id, tof, distance
FROM particle_tracks
WHERE particle_type = 'electron' AND tof > (SELECT AVG(tof) FROM particle_tracks);

SELECT experiment_id, experiment_name, start_date, end_date, principal_investigator, funding_agency, budget
FROM experiments
WHERE start_date < '2022-01-01';

SELECT track_id, experiment_id, particle_type, charge, energy
FROM particle_tracks
WHERE tof > 4000;

SELECT AVG(weight) 
FROM particle_tracks 
WHERE experiment_id = 1;
